const comp = $('Loop competitors').item.json;
const cap = (s, n) => (s || '').toString().replace(/\s+/g, ' ').slice(0, n);
let corpus = 'COMPETITOR: ' + comp.name + ' | aliases: ' + comp.aliases.join(', ') + ' | domain: ' + comp.domain + '\n\n=== GOOGLE RESULTS ===\n';
try {
  const g = $('Apify: Google search').all();
  for (const it of g) {
    const r = it.json;
    if (r.organicResults) { for (const o of r.organicResults.slice(0, 20)) corpus += '- ' + cap(o.title, 150) + ' | ' + o.url + ' | ' + cap(o.description, 250) + '\n'; }
    else if (r.title && r.url) corpus += '- ' + cap(r.title, 150) + ' | ' + r.url + ' | ' + cap(r.description, 250) + '\n';
  }
} catch (e) { corpus += '(google source unavailable)\n'; }
corpus += '\n=== COMPETITOR WEBSITE PAGES ===\n';
try {
  const s = $('Apify: site crawl (JS ok)').all();
  for (const it of s.slice(0, 22)) { const p = it.json; if (p.url) corpus += '\n--- PAGE: ' + p.url + ' ---\n' + cap(p.text || p.markdown, 2600) + '\n'; }
} catch (e) { corpus += '(site source unavailable)\n'; }
corpus += '\n=== LINKEDIN COMPANY POSTS ===\n';
try {
  const l = $('Apify: LinkedIn posts').all();
  for (const it of l.slice(0, 40)) { const p = it.json; const t = p.text || (p.post && p.post.text) || ''; const u = p.url || p.post_url || (p.post && p.post.url) || ''; if (t) corpus += '- ' + cap(t, 400) + ' | ' + u + '\n'; }
} catch (e) { corpus += '(linkedin source unavailable)\n'; }
corpus = corpus.slice(0, 120000);
return [{ json: { competitor: comp.name, corpus } }];

const comp = $('Loop competitors').item.json;
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
let out = [];
let txt = '';
try { txt = $json.content[0].text; } catch (e) { txt = ''; }
let data = { confirmed: [], unverified: [] };
try {
  const m = txt.match(/\{[\s\S]*\}/);
  if (m) data = JSON.parse(m[0]);
} catch (e) {
  out.push({ json: { _sheet: 'unverified', Competitor: comp.name, Event: 'PARSE ERROR', Year: '', Hint: '', Reason: ('model output not JSON: ' + txt.slice(0, 180)), ScannedAt: now } });
}
for (const r of (data.confirmed || [])) out.push({ json: { _sheet: 'confirmed', Competitor: comp.name, Event: r.event, Year: r.year, Status: r.status, Role: r.role, Evidence: r.evidence_quote, Confidence: r.confidence, SourceURL: r.source_url, ScannedAt: now } });
for (const r of (data.unverified || [])) out.push({ json: { _sheet: 'unverified', Competitor: comp.name, Event: r.event, Year: r.year, Hint: r.hint, Reason: r.reason, ScannedAt: now } });
if (out.length === 0) out.push({ json: { _sheet: 'unverified', Competitor: comp.name, Event: '(no signals found)', Year: '', Hint: '', Reason: 'no event signals in corpus', ScannedAt: now } });
return out;
